const messageRaw = $json.message || "";
const message = messageRaw.toLowerCase();

let intent = "unknown";

if (
  message.includes("critical") ||
  message.includes("major") ||
  message.includes("minor") ||
  message.includes("warning")
) {
  intent = "severity_breakdown";
} else if (
  message.includes("power off") ||
  message.includes("site power") ||
  message.includes("power alarm") ||
  message.includes("power alarms") ||
  message.includes("power")
) {
  intent = "power_alarm";
} else if (
  message.includes("unack") ||
  message.includes("not acknowledged") ||
  message.includes("acknowledged")
) {
  intent = "unack_alarm";
} else if (
  (message.includes("site") && message.includes("down")) ||
  message.includes("network down") ||
  message.includes("outage")
) {
  intent = "sites_down";
} else if (message.includes("how many") && message.includes("alarm")) {
  intent = "alarm_count";
} else if (message.includes("vip")) {
  intent = "vip_sites";
} else if (message.includes("top") && message.includes("site")) {
  intent = "top_sites";
} else if (
  message.includes("fm office") ||
  message.includes("office") ||
  message.includes("region") ||
  message.includes("location")
) {
  intent = "fm_office";
} else if (
  message.includes("domain") ||
  message.includes("network type") ||
  message.includes("2g") ||
  message.includes("3g") ||
  message.includes("4g") ||
  message.includes("5g") ||
  message.includes("tx") ||
  message.includes("transmission") ||
  message.includes("ran")
) {
  intent = "domain_breakdown";
} else if (
  message.includes("older than") ||
  message.includes("more than") ||
  message.includes("hours") ||
  message.includes("oldest") ||
  message.includes("aging")
) {
  intent = "aging";
}

const flags = {
  asksDown: message.includes("down") || message.includes("outage"),
  asksPower: message.includes("power"),
  asksVip: message.includes("vip"),
  asks5g: message.includes("5g"),
  asks4g: message.includes("4g"),
  asks3g: message.includes("3g"),
  asks2g: message.includes("2g"),
  asksTx: message.includes("tx") || message.includes("transmission"),
  asksRan: message.includes("ran"),
  asksCritical: message.includes("critical"),
  asksMajor: message.includes("major"),
  asksMinor: message.includes("minor"),
  asksWarning: message.includes("warning"),
};

return [
  {
    json: {
      message: messageRaw,
      intent,
      flags
    }
  }
];

