const total = $json.total || 0;

const intent = $('detect-intent').first().json.intent || $json.intent || "";
const start = $('build_time_range').first().json.start_local || "";
const end = $('build_time_range').first().json.end_local || "";

let answer = "";

if (intent === "sites_down") {
  answer = `Sites Down Summary
Total Down Sites: ${total}
Time Range: ${start} → ${end}`;
} else if (intent === "alarm_count") {
  answer = `Alarm Summary
Total Alarms: ${total}
Time Range: ${start} → ${end}`;
} else if (intent === "severity_breakdown") {
  const sev = $('build_query_severity').first().json.standardalarmseverity || "Selected";
  answer = `Severity Summary
Total ${sev} Alarms: ${total}
Time Range: ${start} → ${end}`;
} else if (intent === "power_alarm") {
  answer = `Power Alarm Summary
Total Power Alarms: ${total}
Time Range: ${start} → ${end}`;
} else {
  answer = `Alarm Summary
Total: ${total}
Time Range: ${start} → ${end}`;
}

return [
  {
    json: {
      answer,
      value: total,
      intent
    }
  }
];

const message = ($json.message || "").toLowerCase();
const now = new Date();

let startDate = new Date(now);
let endDate = new Date(now);

// default = today local full day
startDate.setHours(0, 0, 0, 0);
endDate.setHours(23, 59, 59, 999);

// custom ranges
if (message.includes("last 1 hour") || message.includes("last hour")) {
  endDate = new Date(now);
  startDate = new Date(now.getTime() - 1 * 60 * 60 * 1000);
} else if (message.includes("last 6 hours")) {
  endDate = new Date(now);
  startDate = new Date(now.getTime() - 6 * 60 * 60 * 1000);
} else if (message.includes("last 12 hours")) {
  endDate = new Date(now);
  startDate = new Date(now.getTime() - 12 * 60 * 60 * 1000);
} else if (message.includes("last 24 hours")) {
  endDate = new Date(now);
  startDate = new Date(now.getTime() - 24 * 60 * 60 * 1000);
} else if (message.includes("yesterday")) {
  startDate = new Date(now);
  startDate.setDate(startDate.getDate() - 1);
  startDate.setHours(0, 0, 0, 0);

  endDate = new Date(now);
  endDate.setDate(endDate.getDate() - 1);
  endDate.setHours(23, 59, 59, 999);
} else if (message.includes("last 7 days")) {
  endDate = new Date(now);
  startDate = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
}

function formatLocal(d) {
  const pad = (n) => String(n).padStart(2, "0");
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
}

return [
  {
    json: {
      ...$json,
      start: 0,
      limit: 100,
      type: 1,
      starttime: startDate.getTime(),
      endtime: endDate.getTime(),
      start_local: formatLocal(startDate),
      end_local: formatLocal(endDate)
    }
  }
];

const raw = $json;

// Try to detect total from common shapes
let total = 0;

if (typeof raw.total !== 'undefined') {
  total = Number(raw.total) || 0;
} else if (Array.isArray(raw.result)) {
  total = raw.result.length;
} else if (Array.isArray(raw.data)) {
  total = raw.data.length;
} else if (Array.isArray(raw.rows)) {
  total = raw.rows.length;
}

// Try to extract records
const records =
  Array.isArray(raw.result) ? raw.result :
  Array.isArray(raw.data) ? raw.data :
  Array.isArray(raw.rows) ? raw.rows :
  [];

return [
  {
    json: {
      total,
      records,
      raw
    }
  }
];

const flags = $json.flags || {};

let standardalarmseverity = "";

if (flags.asksCritical) standardalarmseverity = "Critical";
else if (flags.asksMajor) standardalarmseverity = "Major";
else if (flags.asksMinor) standardalarmseverity = "Minor";
else if (flags.asksWarning) standardalarmseverity = "Warning";

return [
  {
    json: {
      ...$json,
      severity: "Uncleared",
      standardalarmseverity
    }
  }
];
